const { body, param, query } = require('express-validator');
const asyncHandler = require('express-async-handler');
const { validateRequest } = require('../middleware/validateRequest');
const { authenticateToken } = require('../middleware/auth');
const db = require('../config/database');
const logger = require('../utils/logger');

const validateDeviceOwnership = asyncHandler(async (req, res, next) => {
  const device = await db.query('SELECT owner_id FROM devices WHERE id = $1', [req.params.id]);

  if (device.rows.length === 0) {
    return res.status(404).json({ error: 'Device not found' });
  }

  if (device.rows[0].owner_id !== req.user.id) {
    return res.status(403).json({ error: 'Access denied' });
  }

  next();
});

const registerDevice = asyncHandler(async (req, res) => {
  const { imei, enrollment_token, dealer_id } = req.body;

  if (!imei || !enrollment_token || !dealer_id) {
    return res.status(400).json({ error: 'IMEI, enrollment token, and dealer ID are required' });
  }

  if (!/^\d{15}$/.test(imei)) {
    return res.status(400).json({ error: 'Invalid IMEI format' });
  }

  const existing = await db.query('SELECT id FROM devices WHERE imei = $1', [imei]);

  if (existing.rows.length > 0) {
    return res.status(409).json({ error: 'Device already registered' });
  }

  const result = await db.query(
    `INSERT INTO devices (imei, enrollment_token, dealer_id, status, created_at)
     VALUES ($1, $2, $3, 'pending', NOW())
     RETURNING id, imei, status`,
    [imei, enrollment_token, dealer_id]
  );

  logger.info(`Device registered: ${imei}`);
  res.status(201).json(result.rows[0]);
});

const getDevice = asyncHandler(async (req, res) => {
  const result = await db.query(
    `SELECT d.*, u.name as owner_name, u.phone as owner_phone
     FROM devices d
     LEFT JOIN users u ON d.owner_id = u.id
     WHERE d.id = $1`,
    [req.params.id]
  );

  if (result.rows.length === 0) {
    return res.status(404).json({ error: 'Device not found' });
  }

  res.json(result.rows[0]);
});

const getMyDevices = asyncHandler(async (req, res) => {
  const result = await db.query(
    `SELECT id, imei, model, brand, status, monthly_amount, emi_remaining, created_at
     FROM devices WHERE owner_id = $1 ORDER BY created_at DESC`,
    [req.user.id]
  );

  res.json(result.rows);
});

const updateDeviceStatus = asyncHandler(async (req, res) => {
  const { status, reason } = req.body;

  const validStatuses = ['active', 'locked', 'unlocked', 'stolen', 'disabled'];
  if (!validStatuses.includes(status)) {
    return res.status(400).json({ error: 'Invalid status' });
  }

  const result = await db.query(
    `UPDATE devices SET status = $1, updated_at = NOW()
     WHERE id = $2 AND (owner_id = $3 OR $3 = ANY(SELECT role FROM users WHERE id = $3))
     RETURNING *`,
    [status, req.params.id, req.user.id]
  );

  if (result.rows.length === 0) {
    return res.status(404).json({ error: 'Device not found or access denied' });
  }

  logger.info(`Device ${req.params.id} status changed to ${status}: ${reason}`);
  res.json(result.rows[0]);
});

const lockDevice = asyncHandler(async (req, res) => {
  const { reason } = req.body;

  const result = await db.query(
    `UPDATE devices SET status = 'locked', updated_at = NOW()
     WHERE id = $1 AND owner_id = $2
     RETURNING *`,
    [req.params.id, req.user.id]
  );

  if (result.rows.length === 0) {
    return res.status(404).json({ error: 'Device not found or not owned by you' });
  }

  logger.warn(`Device ${req.params.id} locked: ${reason}`);
  res.json({ message: 'Device locked successfully', device: result.rows[0] });
});

const unlockDevice = asyncHandler(async (req, res) => {
  const { reason } = req.body;

  const result = await db.query(
    `UPDATE devices SET status = 'active', updated_at = NOW()
     WHERE id = $1 AND owner_id = $2 AND status = 'locked'
     RETURNING *`,
    [req.params.id, req.user.id]
  );

  if (result.rows.length === 0) {
    return res.status(400).json({ error: 'Device not found, not locked, or not owned by you' });
  }

  logger.info(`Device ${req.params.id} unlocked: ${reason}`);
  res.json({ message: 'Device unlocked successfully', device: result.rows[0] });
});

module.exports = {
  registerDevice,
  getDevice,
  getMyDevices,
  updateDeviceStatus,
  lockDevice,
  unlockDevice,
  validateDeviceOwnership
};

require('dotenv').config();
require('express-async-errors');

// Prevent ioredis/Bull subscriber connection drops from crashing the process
process.on('uncaughtException', (err) => {
  if (
    err.message &&
    (err.message.includes('ECONNRESET') ||
      err.message.includes('MaxRetriesPerRequest') ||
      err.message.includes('enableOfflineQueue'))
  ) {
    console.warn('Suppressed Redis connection error (non-fatal):', err.message);
    return;
  }
  console.error('Uncaught exception (fatal):', err);
  process.exit(1);
});
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});

// 1. Load environment config (fail fast if required vars missing)
validateEnvironment();

// 2. Connect PostgreSQL

// 3. Connect Redis

const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const morgan = require('morgan');
const redis = require('./config/redis');
const { pool } = require('./config/database');
const { validateEnvironment } = require('./config/envValidator');
const logger = require('./utils/logger');
const errorHandler = require('./middleware/errorHandler');
const routes = require('./routes');

// Module Schedulers/Init
const { lockSchedulerService } = require('./modules/lock');
const { initLocationModule } = require('./modules/location');
const { initDecouplingModule } = require('./modules/decoupling');
const { initKeyCronJobs } = require('./modules/keys/keyScheduler');
const { initFraudCronJobs } = require('./modules/fraud');

const app = express();
app.set('trust proxy', 1);

// 4. Apply global middleware
app.use(helmet());
const allowedOrigins = (process.env.CORS_ORIGINS || '')
  .split(',')
  .map((o) => o.trim())
  .filter(Boolean);
const allowLocalhostCors =
  process.env.ALLOW_LOCALHOST_CORS === 'true' || process.env.NODE_ENV !== 'production';

function isLoopbackOrigin(origin) {
  try {
    const { hostname } = new URL(origin);
    return hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '::1';
  } catch (err) {
    return false;
  }
}

app.use(
  cors({
    origin: (origin, callback) => {
      if (
        !origin ||
        allowedOrigins.includes(origin) ||
        (allowLocalhostCors && isLoopbackOrigin(origin))
      ) {
        callback(null, true);
      } else {
        callback(new Error(`CORS: origin ${origin} not allowed`));
      }
    },
    credentials: true
  })
);
app.use(express.json({ limit: '1mb' }));
app.use(
  morgan('combined', {
    stream: {
      write: (message) => logger.info(message.trim())
    }
  })
);

/**
 * 5. Health check endpoint: GET /health
 * Returns 200 OK only if DB and Redis are connected
 */
app.get('/health', async (req, res) => {
  let dbStatus = 'disconnected';
  let redisStatus = 'disconnected';

  let dbErrorMsg = null;

  try {
    await pool.query('SELECT 1');
    dbStatus = 'connected';
  } catch (err) {
    dbErrorMsg = err.message;
    logger.error('Health check database error:', err);
  }

  try {
    const pong = await redis.ping();
    if (pong === 'PONG') redisStatus = 'connected';
  } catch (err) {
    logger.error('Health check redis error:', err);
  }

  const isHealthy = dbStatus === 'connected' && redisStatus === 'connected';

  res.status(isHealthy ? 200 : 503).json({
    status: isHealthy ? 'ok' : 'error',
    timestamp: new Date().toISOString(),
    db: dbStatus,
    db_error: dbErrorMsg,
    redis: redisStatus
  });
});

// 6. Register all module routers under /api/v1/
app.use('/api/v1', routes);

// 7. Register error handler LAST
app.use(errorHandler);

// 8. Listen on PORT and start schedulers
const PORT = process.env.PORT || 3000;
let server;

const startServer = async () => {
  try {
    // Start Bull queue schedulers and other cron jobs
    lockSchedulerService.start();
    await initLocationModule();
    initDecouplingModule();
    initKeyCronJobs();
    initFraudCronJobs();

    logger.info('All module schedulers initialized');

    server = app.listen(PORT, () => {
      logger.info(`EMI Locker API running on port ${PORT} in ${process.env.NODE_ENV} mode`);
    });
  } catch (err) {
    logger.error('Failed to start server:', err);
    process.exit(1);
  }
};

startServer();

// Graceful shutdown
const gracefulShutdown = async (signal) => {
  logger.info(`${signal} received. Shutting down gracefully...`);

  if (server) {
    server.close(async () => {
      try {
        await pool.end();
        await redis.quit();
        process.exit(0);
      } catch (err) {
        logger.error('Error during graceful shutdown:', err);
        process.exit(1);
      }
    });
  } else {
    process.exit(0);
  }
};

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

module.exports = app;

const ROLES = {
  ADMIN: 'admin',
  RESELLER: 'reseller',
  DEALER: 'dealer',
  CUSTOMER: 'customer'
};

const ROLE_HIERARCHY = {
  [ROLES.ADMIN]: 4,
  [ROLES.RESELLER]: 3,
  [ROLES.DEALER]: 2,
  [ROLES.CUSTOMER]: 1
};

const PERMISSIONS = {
  USERS_CREATE: 'users:create',
  USERS_READ: 'users:read',
  USERS_UPDATE: 'users:update',
  USERS_DELETE: 'users:delete',
  DEVICES_ENROLL: 'devices:enroll',
  DEVICES_READ: 'devices:read',
  DEVICES_UPDATE: 'devices:update',
  DEVICES_DELETE: 'devices:delete',
  DEVICES_LOCK: 'devices:lock',
  DEVICES_UNLOCK: 'devices:unlock',
  DEVICES_DECOUPLE: 'devices:decouple',
  KEYS_CREATE: 'keys:create',
  KEYS_READ: 'keys:read',
  KEYS_ASSIGN: 'keys:assign',
  PAYMENTS_READ: 'payments:read',
  PAYMENTS_CREATE: 'payments:create',
  EMI_READ: 'emi:read',
  EMI_CREATE: 'emi:create',
  EMI_UPDATE: 'emi:update',
  REPORTS_READ: 'reports:read',
  ADMIN_ALL: 'admin:all'
};

const ROLE_PERMISSIONS = {
  [ROLES.ADMIN]: [
    PERMISSIONS.ADMIN_ALL,
    PERMISSIONS.USERS_CREATE,
    PERMISSIONS.USERS_READ,
    PERMISSIONS.USERS_UPDATE,
    PERMISSIONS.USERS_DELETE,
    PERMISSIONS.DEVICES_ENROLL,
    PERMISSIONS.DEVICES_READ,
    PERMISSIONS.DEVICES_UPDATE,
    PERMISSIONS.DEVICES_DELETE,
    PERMISSIONS.DEVICES_LOCK,
    PERMISSIONS.DEVICES_UNLOCK,
    PERMISSIONS.DEVICES_DECOUPLE,
    PERMISSIONS.KEYS_CREATE,
    PERMISSIONS.KEYS_READ,
    PERMISSIONS.KEYS_ASSIGN,
    PERMISSIONS.PAYMENTS_READ,
    PERMISSIONS.PAYMENTS_CREATE,
    PERMISSIONS.EMI_READ,
    PERMISSIONS.EMI_CREATE,
    PERMISSIONS.EMI_UPDATE,
    PERMISSIONS.REPORTS_READ
  ],
  [ROLES.RESELLER]: [
    PERMISSIONS.USERS_CREATE,
    PERMISSIONS.USERS_READ,
    PERMISSIONS.USERS_UPDATE,
    PERMISSIONS.DEVICES_READ,
    PERMISSIONS.KEYS_CREATE,
    PERMISSIONS.KEYS_READ,
    PERMISSIONS.KEYS_ASSIGN,
    PERMISSIONS.PAYMENTS_READ,
    PERMISSIONS.REPORTS_READ
  ],
  [ROLES.DEALER]: [
    PERMISSIONS.USERS_READ,
    PERMISSIONS.USERS_UPDATE,
    PERMISSIONS.DEVICES_ENROLL,
    PERMISSIONS.DEVICES_READ,
    PERMISSIONS.DEVICES_UPDATE,
    PERMISSIONS.DEVICES_LOCK,
    PERMISSIONS.KEYS_READ,
    PERMISSIONS.KEYS_ASSIGN,
    PERMISSIONS.PAYMENTS_READ,
    PERMISSIONS.EMI_READ,
    PERMISSIONS.EMI_CREATE,
    PERMISSIONS.EMI_UPDATE
  ],
  [ROLES.CUSTOMER]: [
    PERMISSIONS.DEVICES_READ,
    PERMISSIONS.DEVICES_UNLOCK,
    PERMISSIONS.PAYMENTS_READ,
    PERMISSIONS.EMI_READ,
    PERMISSIONS.EMI_UPDATE
  ]
};

function requireRole(...roles) {
  const allowedRoles = Array.isArray(roles[0]) ? roles[0] : roles;

  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json(buildErrorResponse(401, 'AUTHENTICATION_REQUIRED', 'Authentication required'));
    }

    const userRole = req.user.role;

    if (!allowedRoles.includes(userRole)) {
      return res.status(403).json(buildErrorResponse(403, 'INSUFFICIENT_PERMISSIONS', 'Insufficient permissions'));
    }

    next();
  };
}

function requirePermission(...permissions) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json(buildErrorResponse(401, 'AUTHENTICATION_REQUIRED', 'Authentication required'));
    }

    const userRole = req.user.role;
    const userPermissions = ROLE_PERMISSIONS[userRole] || [];

    const hasAllPermissions = permissions.every(perm =>
      userPermissions.includes(perm) || userPermissions.includes(PERMISSIONS.ADMIN_ALL)
    );

    if (!hasAllPermissions) {
      return res.status(403).json(buildErrorResponse(403, 'INSUFFICIENT_PERMISSIONS', 'Insufficient permissions'));
    }

    next();
  };
}

function requireMinRole(minRole) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json(buildErrorResponse(401, 'AUTHENTICATION_REQUIRED', 'Authentication required'));
    }

    const userRoleLevel = ROLE_HIERARCHY[req.user.role] || 0;
    const requiredLevel = ROLE_HIERARCHY[minRole] || 0;

    if (userRoleLevel < requiredLevel) {
      return res.status(403).json(buildErrorResponse(403, 'INSUFFICIENT_PERMISSIONS', 'Insufficient permissions'));
    }

    next();
  };
}

function requireAnyRole(...roles) {
  return requireRole(...roles);
}

function requireAllRoles(...roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json(buildErrorResponse(401, 'AUTHENTICATION_REQUIRED', 'Authentication required'));
    }

    const hasAllRoles = roles.every(role => req.user.role === role);

    if (!hasAllRoles) {
      return res.status(403).json(buildErrorResponse(403, 'INSUFFICIENT_PERMISSIONS', 'Insufficient permissions'));
    }

    next();
  };
}

function isAdmin(req, res, next) {
  return requireRole(ROLES.ADMIN)(req, res, next);
}

function isResellerOrAbove(req, res, next) {
  return requireMinRole(ROLES.RESELLER)(req, res, next);
}

function isDealerOrAbove(req, res, next) {
  return requireMinRole(ROLES.DEALER)(req, res, next);
}

module.exports = {
  ROLES,
  PERMISSIONS,
  ROLE_HIERARCHY,
  ROLE_PERMISSIONS,
  requireRole,
  requirePermission,
  requireMinRole,
  requireAnyRole,
  requireAllRoles,
  isAdmin,
  isResellerOrAbove,
  isDealerOrAbove
};
const { buildErrorResponse } = require('./errorHandler');

const db = require('../../config/database');
const logger = require('../../utils/logger');
const { emitKeyRequestApproved } = require('../sse/sseService');

class AdminDeviceService {
  mapDevice(row) {
    if (!row) return null;

    return {
      ...row,
      deviceId: row.id,
      dealerId: row.dealer_id,
      lockState: row.lock_level || (row.status === 'locked' ? 'FULL_LOCK' : 'UNLOCKED'),
      isOverdue: false,
      overdueDays: 0,
      createdAt: row.created_at,
      updatedAt: row.updated_at
    };
  }

  async getAllDevices(filters = {}) {
    const client = await db.connect();
    try {
      let query = `
        SELECT d.*,
          u.name as owner_name, u.phone as owner_phone, u.email as owner_email,
          dl.name as dealer_name, dl.phone as dealer_phone,
          e.emi_amount, e.total_amount, e.duration,
          (SELECT COUNT(*) FROM emi_payments p WHERE p.device_id = d.id) as payment_count,
          (SELECT MAX(p.recorded_at) FROM emi_payments p WHERE p.device_id = d.id) as last_payment_date
        FROM devices d
        LEFT JOIN users u ON d.owner_id = u.id
        LEFT JOIN dealers dl ON d.dealer_id = dl.id
        LEFT JOIN emi_schedules e ON d.id = e.device_id
        WHERE d.status != 'decoupled'
      `;

      const params = [];
      let paramCount = 0;

      if (filters.status) {
        paramCount++;
        query += ` AND d.status = $${paramCount}`;
        params.push(filters.status);
      }

      if (filters.dealerId) {
        paramCount++;
        query += ` AND d.dealer_id = $${paramCount}`;
        params.push(filters.dealerId);
      }

      if (filters.imei) {
        paramCount++;
        query += ` AND d.imei ILIKE $${paramCount}`;
        params.push(`%${filters.imei}%`);
      }

      if (filters.search) {
        paramCount++;
        query += ` AND (u.name ILIKE $${paramCount} OR u.phone ILIKE $${paramCount} OR d.imei ILIKE $${paramCount} OR d.model ILIKE $${paramCount})`;
        params.push(`%${filters.search}%`);
      }

      query += ' ORDER BY d.created_at DESC';

      if (filters.limit) {
        paramCount++;
        query += ` LIMIT $${paramCount}`;
        params.push(filters.limit);
      } else {
        query += ' LIMIT 100';
      }

      if (filters.offset) {
        paramCount++;
        query += ` OFFSET $${paramCount}`;
        params.push(filters.offset);
      }

      const result = await client.query(query, params);

      let countQuery = `SELECT COUNT(*) FROM devices d
        LEFT JOIN users u ON d.owner_id = u.id
        LEFT JOIN dealers dl ON d.dealer_id = dl.id
        LEFT JOIN emi_schedules e ON d.id = e.device_id
        WHERE d.status != 'decoupled'`;
      const countParams = [];
      let countParamCount = 0;

      if (filters.status) {
        countParamCount++;
        countQuery += ` AND d.status = $${countParamCount}`;
        countParams.push(filters.status);
      }

      if (filters.dealerId) {
        countParamCount++;
        countQuery += ` AND d.dealer_id = $${countParamCount}`;
        countParams.push(filters.dealerId);
      }

      if (filters.resellerId) {
        countParamCount++;
        countQuery += ` AND dl.reseller_id = $${countParamCount}`;
        countParams.push(filters.resellerId);
      }

      if (filters.imei) {
        countParamCount++;
        countQuery += ` AND d.imei ILIKE $${countParamCount}`;
        countParams.push(`%${filters.imei}%`);
      }

      if (filters.search) {
        countParamCount++;
        countQuery += ` AND (u.name ILIKE $${countParamCount} OR u.phone ILIKE $${countParamCount} OR d.imei ILIKE $${countParamCount} OR d.model ILIKE $${countParamCount})`;
        countParams.push(`%${filters.search}%`);
      }

      if (filters.emiStatus) {
        countParamCount++;
        countQuery += ` AND e.status = $${countParamCount}`;
        countParams.push(filters.emiStatus);
      }

      const countResult = await client.query(countQuery, countParams);

      return {
        devices: result.rows.map((row) => this.mapDevice(row)),
        total: parseInt(countResult.rows[0].count, 10),
        filters
      };
    } finally {
      client.release();
    }
  }

  async getDeviceById(deviceId) {
    const client = await db.connect();
    try {
      const result = await client.query(
        `SELECT d.*,
                u.name as owner_name, u.phone as owner_phone, u.email as owner_email,
                dl.name as dealer_name, dl.phone as dealer_phone
         FROM devices d
         LEFT JOIN users u ON d.owner_id = u.id
         LEFT JOIN dealers dl ON d.dealer_id = dl.id
         WHERE d.id = $1`,
        [deviceId]
      );

      return this.mapDevice(result.rows[0]);
    } finally {
      client.release();
    }
  }

  async lockDevice(deviceId, adminId, reason, ipAddress, lockLevel = 'soft') {
    const client = await db.connect();
    try {
      await client.query('BEGIN');

      const deviceResult = await client.query('SELECT * FROM devices WHERE id = $1', [deviceId]);

      if (deviceResult.rows.length === 0) {
        await client.query('ROLLBACK');
        return { success: false, error: 'Device not found' };
      }

      const device = deviceResult.rows[0];

      if (device.status === 'locked') {
        await client.query('ROLLBACK');
        return { success: false, error: 'Device is already locked' };
      }

      if (device.status === 'decoupled') {
        await client.query('ROLLBACK');
        return { success: false, error: 'Cannot lock a decoupled device' };
      }

      const updateResult = await client.query(
        `UPDATE devices SET status = 'locked', lock_reason = $1, locked_by = $2, locked_at = NOW(), lock_level = $3, updated_at = NOW()
         WHERE id = $4 RETURNING *`,
        [reason, adminId, lockLevel, deviceId]
      );

      let signedCommand = null;
      try {
        const firebaseService = require('../devices/firebaseService');
        await firebaseService.updateLockState(deviceId, 'locked', {
          reason,
          lockedBy: adminId,
          adminLock: true,
          lockLevel
        });

        const commandSigningService = require('../devices/commandSigningService');
        signedCommand = await commandSigningService.createAndStoreSignedCommand(
          deviceId,
          'admin_lock',
          { reason, lockedBy: adminId, lockLevel },
          device.imei,
          { serial_number: device.serial_number, soc_id: device.soc_id }
        );
      } catch (error) {
        logger.warn('Admin lock command delivery skipped:', error.message);
      }

      await client.query(
        `INSERT INTO audit_log (actor, action, target_type, target_id, metadata, ip_address, created_at)
         VALUES ($1, 'DEVICE_LOCKED_BY_ADMIN', 'device', $2, $3, $4, NOW())`,
        [
          adminId,
          deviceId,
          JSON.stringify({ deviceId, reason, lockLevel, lockedAt: new Date(), adminId }),
          ipAddress
        ]
      );

      await client.query('COMMIT');

      logger.info(`Admin ${adminId} locked device ${deviceId}: ${reason} (${lockLevel})`);

      return {
        success: true,
        device: this.mapDevice(updateResult.rows[0]),
        command: signedCommand
      };
    } catch (error) {
      await client.query('ROLLBACK');
      logger.error('Failed to lock device:', error);
      throw error;
    } finally {
      client.release();
    }
  }

  async unlockDevice(deviceId, adminId, reason, ipAddress) {
    const client = await db.connect();
    try {
      await client.query('BEGIN');

      const deviceResult = await client.query('SELECT * FROM devices WHERE id = $1', [deviceId]);

      if (deviceResult.rows.length === 0) {
        await client.query('ROLLBACK');
        return { success: false, error: 'Device not found' };
      }

      const device = deviceResult.rows[0];

      if (device.status !== 'locked') {
        await client.query('ROLLBACK');
        return { success: false, error: 'Device is not locked' };
      }

      const updateResult = await client.query(
        `UPDATE devices SET status = 'unlocked', lock_reason = NULL, locked_by = NULL, locked_at = NULL, lock_level = NULL, updated_at = NOW()
         WHERE id = $1 RETURNING *`,
        [deviceId]
      );

      let signedCommand = null;
      try {
        const firebaseService = require('../devices/firebaseService');
        await firebaseService.updateLockState(deviceId, 'unlocked', {
          reason,
          unlockedBy: adminId,
          adminUnlock: true
        });

        const commandSigningService = require('../devices/commandSigningService');
        signedCommand = await commandSigningService.createAndStoreSignedCommand(
          deviceId,
          'admin_unlock',
          { reason, unlockedBy: adminId },
          device.imei,
          { serial_number: device.serial_number, soc_id: device.soc_id }
        );
      } catch (error) {
        logger.warn('Admin unlock command delivery skipped:', error.message);
      }

      await client.query(
