  async getDevices({ page = 1, limit = 20, status, dealerId } = {}) {
    const client = await pool.connect();
    try {
      const offset = (page - 1) * limit;
      const conditions = [];
      const params = [];
      let idx = 1;

      if (status) {
        conditions.push(`d.status = $${idx++}`);
        params.push(status);
      }
      if (dealerId) {
        conditions.push(`d.dealer_id = $${idx++}`);
        params.push(dealerId);
      }

      const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

      const rows = await client.query(
        `SELECT d.id, d.imei, d.device_name, d.model, d.brand, d.status, d.lock_level,
                d.created_at, d.updated_at, dl.name as dealer_name
         FROM devices d
         LEFT JOIN dealers dl ON d.dealer_id = dl.id
         ${where} ORDER BY d.created_at DESC LIMIT $${idx++} OFFSET $${idx}`,
        [...params, limit, offset]
      );

      const countResult = await client.query(`SELECT COUNT(*) FROM devices d ${where}`, params);
      const total = parseInt(countResult.rows[0].count, 10);

      return {
        devices: rows.rows,
        pagination: { page, limit, total, pages: Math.ceil(total / limit) }
      };
    } finally {
      client.release();
    }
  }

