        COUNT(ak.id) FILTER (WHERE ak.status IN ('activated','assigned'))::int AS keys_distributed
      FROM resellers r
      LEFT JOIN dealers d ON d.reseller_id = r.id
      LEFT JOIN activation_keys ak ON ak.reseller_id = r.id
      WHERE r.district = $1
