const { rateLimit } = require('express-rate-limit');
const { RedisStore } = require('rate-limit-redis');
const redis = require('../../config/redis');

const RATE_LIMIT_WINDOW = 15 * 60 * 1000;
const MAX_LOGIN_ATTEMPTS = 100;
const MAX_2FA_ATTEMPTS = 100;

function createRedisStore(prefix) {
  // Use memory store by default for local development to prevent boot crashes
  return undefined;
}

function buildErrorPayload(message, code = 'RATE_LIMITED') {
  return {
    status: 'error',
    code,
    message
  };
}

const loginLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  limit: MAX_LOGIN_ATTEMPTS,
  standardHeaders: 'draft-7',
  legacyHeaders: false,
  store: createRedisStore('rl:login:'),
  handler: (req, res) => {
    const retryAfter = req.rateLimit?.resetTime
      ? Math.max(1, Math.ceil((req.rateLimit.resetTime.getTime() - Date.now()) / 1000))
      : Math.ceil(RATE_LIMIT_WINDOW / 1000);

    res.set('Retry-After', String(retryAfter));
    return res.status(429).json(buildErrorPayload('Too many login attempts. Please try again later.'));
  }
});

const verify2FALimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  limit: MAX_2FA_ATTEMPTS,
  standardHeaders: 'draft-7',
  legacyHeaders: false,
  store: createRedisStore('rl:2fa:'),
  handler: (req, res) => {
    const retryAfter = req.rateLimit?.resetTime
      ? Math.max(1, Math.ceil((req.rateLimit.resetTime.getTime() - Date.now()) / 1000))
      : Math.ceil(RATE_LIMIT_WINDOW / 1000);

    res.set('Retry-After', String(retryAfter));
    return res.status(429).json(buildErrorPayload('Too many 2FA verification attempts. Please try again later.'));
  }
});

module.exports = {
  RATE_LIMIT_WINDOW,
  MAX_LOGIN_ATTEMPTS,
  MAX_2FA_ATTEMPTS,
  loginLimiter,
  verify2FALimiter
};

const bcrypt = require('bcryptjs');
const crypto = require('crypto');
const speakeasy = require('speakeasy');
const db = require('../../config/database');
const logger = require('../../utils/logger');

const BACKUP_CODE_COUNT = 8;
const ENCRYPTION_PREFIX = 'enc:';

function getEncryptionKey() {
  const source =
    process.env.TOTP_ENCRYPTION_KEY ||
    process.env.JWT_PRIVATE_KEY ||
    process.env.JWT_SECRET ||
    'emi-locker-development-totp-key';

  return crypto.createHash('sha256').update(source).digest();
}

function encryptSecret(secret) {
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', getEncryptionKey(), iv);
  const encrypted = Buffer.concat([cipher.update(secret, 'utf8'), cipher.final()]);
  const authTag = cipher.getAuthTag();

  return `${ENCRYPTION_PREFIX}${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted.toString('hex')}`;
}

function decryptSecret(secret) {
  if (!secret) return null;
  if (!secret.startsWith(ENCRYPTION_PREFIX)) return secret;

  const [, encoded] = secret.split(ENCRYPTION_PREFIX);
  const [ivHex, authTagHex, encryptedHex] = encoded.split(':');
  const decipher = crypto.createDecipheriv(
    'aes-256-gcm',
    getEncryptionKey(),
    Buffer.from(ivHex, 'hex')
  );

  decipher.setAuthTag(Buffer.from(authTagHex, 'hex'));
  const decrypted = Buffer.concat([
    decipher.update(Buffer.from(encryptedHex, 'hex')),
    decipher.final()
  ]);

  return decrypted.toString('utf8');
}

function generateTOTP(email, role) {
  const secret = speakeasy.generateSecret({
    name: `EMI Locker (${role.toUpperCase()}):${email}`,
    issuer: 'EMI Locker',
    length: 20
  });

  return {
    secret: secret.base32,
    otpauthUrl: secret.otpauth_url
  };
}

function verifyTOTP(code, storedSecret) {
  if (!code || !storedSecret) return false;

  const normalizedCode = String(code).replace(/\s/g, '');
  if (!/^\d{6}$/.test(normalizedCode)) {
    return false;
  }

  try {
    return speakeasy.totp.verify({
      secret: decryptSecret(storedSecret),
      encoding: 'base32',
      token: normalizedCode,
      window: 1
    });
  } catch (error) {
    logger.error('TOTP verification failed:', error);
    return false;
  }
}

async function setup(userId, email, role) {
  const { secret, otpauthUrl } = generateTOTP(email, role);
  const encryptedSecret = encryptSecret(secret);

  await db.query(
    'UPDATE users SET totp_secret = $1, totp_pending = $2, updated_at = NOW() WHERE id = $3',
    [encryptedSecret, true, userId]
  );

  return { secret, otpauthUrl };
}

async function verify(userId, token) {
  const result = await db.query('SELECT totp_secret FROM users WHERE id = $1', [userId]);
  if (result.rows.length === 0 || !result.rows[0].totp_secret) {
    return false;
  }

  return verifyTOTP(token, result.rows[0].totp_secret);
}

function normalizeBackupCode(code) {
  return String(code).toUpperCase().replace(/\s/g, '');
}

function generateSingleBackupCode() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  const bytes = crypto.randomBytes(8);
  let code = '';

  for (let i = 0; i < 8; i += 1) {
    if (i > 0 && i % 4 === 0) {
      code += '-';
    }

    code += chars.charAt(bytes[i] % chars.length);
  }

  return code;
}

async function hashBackupCode(code) {
  return bcrypt.hash(normalizeBackupCode(code), 12);
}

async function generateBackupCodes(userId) {
  const plainCodes = [];
  const hashedCodes = [];

  for (let index = 0; index < BACKUP_CODE_COUNT; index += 1) {
    const code = generateSingleBackupCode();
    plainCodes.push(code);
    hashedCodes.push(await hashBackupCode(code));
  }

  if (userId) {
    await db.query(
      'UPDATE users SET backup_codes = $1, updated_at = NOW() WHERE id = $2',
      [hashedCodes, userId]
    );
  }

  return {
    plain: plainCodes,
    hashed: hashedCodes
  };
}

async function verifyBackupCode(userId, code) {
  const result = await db.query('SELECT backup_codes FROM users WHERE id = $1', [userId]);
  if (result.rows.length === 0) {
    return false;
  }

  const storedCodes = result.rows[0].backup_codes || [];
  const normalizedCode = normalizeBackupCode(code);
  const remainingCodes = [];
  let matched = false;

  for (const storedCode of storedCodes) {
    if (!matched && await bcrypt.compare(normalizedCode, storedCode)) {
      matched = true;
      continue;
    }

    remainingCodes.push(storedCode);
  }

  if (matched) {
    await db.query(
      'UPDATE users SET backup_codes = $1, updated_at = NOW() WHERE id = $2',
      [remainingCodes, userId]
    );
  }

  return matched;
}

module.exports = {
  setup,
  verify,
  generateTOTP,
  verifyTOTP,
  generateBackupCodes,
  generateSingleBackupCode,
  hashBackupCode,
  verifyBackupCode,
  encryptSecret,
  decryptSecret
};

const db = require('../../config/database');
const logger = require('../../utils/logger');

const SCORE_DELTAS = {
  ON_TIME_PAYMENT:    +50,
  LATE_PAYMENT:       -30,
  MISSED_PAYMENT:     -60,
  DEVICE_COMPLETED:   +100,
  FRAUD_CONFIRMED:    -600,
  SIM_CHANGE:         -40,
  ANOMALY_DETECTED:   -25,
  SIM_STABILITY_HIGH: +30,
  MANUAL_ADJUSTMENT:  0,   // delta provided by caller
};

function recalculateTier(score) {
  if (score >= 800) return 'GOLD';
  if (score >= 600) return 'SILVER';
  if (score >= 400) return 'BRONZE';
  if (score >= 200) return 'RED';
  return 'BLACKLISTED';
}

async function lookupByNidHash(nidHash) {
  const profile = await db.query(
    `SELECT score, tier, member_since, devices_completed,
            installments_paid, installments_late, installments_missed,
            fraud_flags, sim_stability, last_activity_month
     FROM customer_credit_profiles
     WHERE nid_hash = $1`,
    [nidHash]
  );

  if (profile.rows.length === 0) return null;

  const p = profile.rows[0];
  const total = p.installments_paid + p.installments_late + p.installments_missed;
  const payment_rate = total > 0
    ? Math.round((p.installments_paid / total) * 100)
    : null;

  return {
    score: p.score,
    tier: p.tier,
    member_since: p.member_since,
    devices_completed: p.devices_completed,
    installments_paid: p.installments_paid,
    installments_late: p.installments_late,
    installments_missed: p.installments_missed,
    payment_rate,
    fraud_flags: p.fraud_flags,
    sim_stability: p.sim_stability,
    last_activity_month: p.last_activity_month,
  };
}

async function recordPaymentEvent(nidHash, eventType, customDelta = null) {
  const delta = customDelta !== null ? customDelta : (SCORE_DELTAS[eventType] ?? 0);

  const currentMonth = new Date().toISOString().slice(0, 7); // YYYY-MM

  const upsertResult = await db.query(
    `INSERT INTO customer_credit_profiles (nid_hash, score, tier, last_activity_month)
     VALUES ($1, $2, $3, $4)
     ON CONFLICT (nid_hash) DO UPDATE SET
       score              = GREATEST(0, LEAST(1000, customer_credit_profiles.score + $5)),
       installments_paid  = CASE WHEN $6 = 'ON_TIME_PAYMENT'  THEN customer_credit_profiles.installments_paid  + 1 ELSE customer_credit_profiles.installments_paid  END,
       installments_late  = CASE WHEN $6 = 'LATE_PAYMENT'     THEN customer_credit_profiles.installments_late  + 1 ELSE customer_credit_profiles.installments_late  END,
       installments_missed= CASE WHEN $6 = 'MISSED_PAYMENT'   THEN customer_credit_profiles.installments_missed + 1 ELSE customer_credit_profiles.installments_missed END,
       devices_completed  = CASE WHEN $6 = 'DEVICE_COMPLETED' THEN customer_credit_profiles.devices_completed + 1 ELSE customer_credit_profiles.devices_completed END,
       fraud_flags        = CASE WHEN $6 = 'FRAUD_CONFIRMED'  THEN customer_credit_profiles.fraud_flags + 1 ELSE customer_credit_profiles.fraud_flags END,
       sim_stability      = CASE WHEN $6 = 'SIM_STABILITY_HIGH' THEN 'HIGH'
                                 WHEN $6 = 'SIM_CHANGE'         THEN 'LOW'
                                 ELSE customer_credit_profiles.sim_stability END,
       last_activity_month= $4,
       updated_at         = NOW()
     RETURNING score`,
    [
      nidHash,
      Math.max(0, Math.min(1000, 500 + delta)), // initial score for new profiles
      recalculateTier(500 + delta),
      currentMonth,
      delta,
      eventType,
    ]
  );

  const newScore = upsertResult.rows[0].score;
  const newTier  = recalculateTier(newScore);

  // Update tier after score change
  await db.query(
    `UPDATE customer_credit_profiles SET tier = $1 WHERE nid_hash = $2`,
    [newTier, nidHash]
  );

  // Permanent audit trail
  await db.query(
    `INSERT INTO credit_score_events (nid_hash, event_type, score_delta, score_after)
     VALUES ($1, $2, $3, $4)`,
    [nidHash, eventType, delta, newScore]
  );

  return { score: newScore, tier: newTier, delta };
}

async function checkBlacklist(nidHash) {
  const result = await db.query(
    `SELECT reason FROM fraud_blacklist WHERE nid_hash = $1 AND active = TRUE`,
    [nidHash]
  );

  if (result.rows.length === 0) return { blacklisted: false };
  return { blacklisted: true, reason: result.rows[0].reason };
}

module.exports = { lookupByNidHash, recordPaymentEvent, recalculateTier, checkBlacklist };

const { v4: uuidv4 } = require('uuid');
const db = require('../../config/database');
const logger = require('../../utils/logger');

const DECOUPLING_STATES = {
  EMI_ACTIVE: 'EMI_ACTIVE',
  FINAL_PAYMENT_RECEIVED: 'FINAL_PAYMENT_RECEIVED',
  DEALER_NOTIFIED: 'DEALER_NOTIFIED',
  FRAUD_FLAGGED: 'FRAUD_FLAGGED',
  FRAUD_CONFIRMED: 'FRAUD_CONFIRMED',
  FRAUD_REJECTED: 'FRAUD_REJECTED',
  PENDING_ADMIN_DECOUPLE: 'PENDING_ADMIN_DECOUPLE',
  DEVICE_DECOUPLED: 'DEVICE_DECOUPLED'
};

// ============================================================
// Valid state transitions — the core of the state machine
// Dealer CANNOT block or delay decoupling.
// Dealer's only role during DEALER_NOTIFIED is to FLAG fraud.
// ============================================================
const VALID_TRANSITIONS = {
  [DECOUPLING_STATES.EMI_ACTIVE]: [DECOUPLING_STATES.FINAL_PAYMENT_RECEIVED],
  [DECOUPLING_STATES.FINAL_PAYMENT_RECEIVED]: [DECOUPLING_STATES.DEALER_NOTIFIED],
  [DECOUPLING_STATES.DEALER_NOTIFIED]: [
    DECOUPLING_STATES.FRAUD_FLAGGED, // dealer raises fraud flag
    DECOUPLING_STATES.PENDING_ADMIN_DECOUPLE // 5-day window expires, no fraud
  ],
  [DECOUPLING_STATES.FRAUD_FLAGGED]: [
    DECOUPLING_STATES.FRAUD_CONFIRMED, // admin confirms fraud
    DECOUPLING_STATES.FRAUD_REJECTED // admin rejects fraud → continues
  ],
  [DECOUPLING_STATES.FRAUD_REJECTED]: [
    DECOUPLING_STATES.PENDING_ADMIN_DECOUPLE // fraud rejected, proceed to admin
  ],
  [DECOUPLING_STATES.FRAUD_CONFIRMED]: [], // terminal — decoupling blocked
  [DECOUPLING_STATES.PENDING_ADMIN_DECOUPLE]: [
    DECOUPLING_STATES.DEVICE_DECOUPLED // admin executes decoupling
  ],
  [DECOUPLING_STATES.DEVICE_DECOUPLED]: [] // terminal — immutable
};

async function beginTransaction() {
  const client = await db.getClient();
  await client.query('BEGIN');
  return client;
}

async function commitTransaction(client) {
  await client.query('COMMIT');
  client.release();
}

async function rollbackTransaction(client) {
  await client.query('ROLLBACK');
  client.release();
}

