  async updateState(deviceId, newState, currentState, additionalData = {}, client = null) {
    const allowedColumns = [
      'dealer_notified_at',
      'fraud_window_started_at',
      'fraud_window_ends_at',
      'fraud_flag',
      'fraud_flagged_by',
      'fraud_flagged_at',
      'fraud_reason',
      'fraud_evidence_url',
      'fraud_confirmed_by',
      'fraud_confirmed_at',
      'fraud_rejected_by',
      'fraud_rejected_at',
      'rtoc_code_hash',
      'rtoc_generated_at',
