const cron = require('node-cron');
const db = require('../../config/database');
const logger = require('../../utils/logger');
const locationService = require('./locationService');

const FULL_LOCK_LEVELS = ['FULL', 'FULL_LOCK', 'WIPE'];

class LocationSchedulerService {
  constructor() {
    this.jobs = [];
    this.started = false;
  }

  start() {
    if (this.started) {
      logger.warn('Location scheduler already started');
      return;
    }

    const job = cron.schedule('0 */6 * * *', async () => {
      logger.info('Scheduled auto-location check triggered');
      await this.checkDevicesInFullLock();
    }, { scheduled: true, timezone: process.env.TZ || 'UTC' });

    this.jobs.push(job);
    this.started = true;
    logger.info('Location scheduler started — auto-location every 6 hours');
  }

  stop() {
    this.jobs.forEach(job => job.stop());
    this.jobs = [];
    this.started = false;
    logger.info('Location scheduler stopped');
  }

  async checkDevicesInFullLock() {
    try {
      const result = await db.query(
        `SELECT d.id, d.imei, d.serial_number, d.fcm_token, d.dealer_id
         FROM devices d
         WHERE d.status = 'locked'
           AND d.lock_level = ANY($1::text[])
           AND d.status != 'decoupled'`,
        [FULL_LOCK_LEVELS]
      );

      logger.info(`Checking ${result.rows.length} devices in Full Lock for auto-location`);

      for (const device of result.rows) {
        try {
          const hasActiveGeofence = await db.query(
            `SELECT id FROM geofences WHERE device_id = $1 AND enabled = true`,
            [device.id]
          );

          if (hasActiveGeofence.rows.length > 0) {
            await locationService.pullLocationNow(device.id, 'scheduled_6h_check_with_geofence', 'system');
          } else {
            await locationService.pullLocationNow(device.id, 'scheduled_6h_check', 'system');
          }
        } catch (error) {
          logger.error(`Failed to process auto-location for device ${device.id}:`, error);
        }
      }

      logger.info('Auto-location check completed');
    } catch (error) {
      logger.error('Auto-location check failed:', error);
    }
  }

  async handleDeviceLockChange(deviceId, lockLevel) {
    if (FULL_LOCK_LEVELS.includes(lockLevel)) {
      logger.info(`Device ${deviceId} entered Full Lock — scheduling auto-location`);
      await locationService.scheduleAutoLocation(deviceId);
    } else {
      logger.info(`Device ${deviceId} exited Full Lock — cancelling auto-location`);
      await locationService.cancelAutoLocation(deviceId);
    }
  }

  async syncScheduledLocations() {
    try {
      const result = await db.query(
        `SELECT d.id, d.imei, d.fcm_token, d.lock_level
         FROM devices d
         WHERE d.status = 'locked'
           AND d.lock_level = ANY($1::text[])
           AND d.status != 'decoupled'`,
        [FULL_LOCK_LEVELS]
      );

      for (const device of result.rows) {
        const hasJob = await this.hasScheduledJob(device.id);
        if (!hasJob) {
          await locationService.scheduleAutoLocation(device.id);
          logger.info(`Re-scheduled auto-location for device ${device.id}`);
        }
      }
    } catch (error) {
      logger.error('Failed to sync scheduled locations:', error);
    }
  }

  async hasScheduledJob(deviceId) {
    try {
      const queue = locationService.getAutoLocationQueue();
      const repeatableJobs = await queue.getRepeatableJobs();
      return repeatableJobs.some(job => job.name === `auto-location-${deviceId}`);
    } catch (error) {
      return false;
    }
  }
}

module.exports = new LocationSchedulerService();

const Queue = require('bull');
const crypto = require('crypto');
const db = require('../../config/database');
const logger = require('../../utils/logger');
const fcmService = require('../notifications/fcm.service');
const deviceService = require('../devices/deviceService');
const kmsSigningService = require('../devices/kmsSigningService');
const { emitLocationReported } = require('../sse/sseService');

const REDIS_URL =
  process.env.BULL_REDIS_URL ||
  process.env.UPSTASH_REDIS_URL ||
  process.env.REDIS_URL ||
  'redis://localhost:6379';
const AUTO_LOCATION_LOCK_LEVELS = new Set(['FULL', 'FULL_LOCK', 'WIPE']);

class LocationService {
  getLocationPullQueue() {
    if (!this._locationPullQueue) {
      this._locationPullQueue = new Queue('location-pull', REDIS_URL, {
        defaultJobOptions: {
          attempts: 3,
          backoff: { type: 'exponential', delay: 2000 },
          removeOnComplete: true,
          removeOnFail: false
        }
      });

      this._locationPullQueue.on('failed', (job, err) => {
        logger.error(`Location pull job ${job.id} failed:`, err.message);
      });

      this._locationPullQueue.on('completed', (job) => {
        logger.info(`Location pull job ${job.id} completed for device ${job.data.deviceId}`);
      });
    }
    return this._locationPullQueue;
  }

  getAutoLocationQueue() {
    if (!this._autoLocationQueue) {
      this._autoLocationQueue = new Queue('auto-location', REDIS_URL, {
        defaultJobOptions: {
          attempts: 3,
          backoff: { type: 'exponential', delay: 2000 },
          removeOnComplete: true,
          removeOnFail: false
        }
      });

      this._autoLocationQueue.on('failed', (job, err) => {
        logger.error(`Auto-location job ${job.id} failed:`, err.message);
      });
    }
    return this._autoLocationQueue;
  }

  async pullLocationNow(deviceId, reason, userId) {
    const device = await deviceService.getDeviceById(deviceId);
    if (!device) {
      throw new Error('Device not found');
    }

    await db.query(
      `UPDATE location_pull_requests
       SET status = 'expired'
       WHERE device_id = $1
         AND status = 'pending'
         AND expires_at <= NOW()`,
      [deviceId]
    );

    const existingPull = await db.query(
      `SELECT pull_id, expires_at
       FROM location_pull_requests
       WHERE device_id = $1
         AND status = 'pending'
         AND expires_at > NOW()
       ORDER BY requested_at DESC
       LIMIT 1`,
      [deviceId]
    );

    await db.query(
      `DELETE FROM location_pull_requests
       WHERE id IN (
         SELECT id FROM location_pull_requests
         WHERE device_id = $1
           AND status IN ('expired', 'completed')
         ORDER BY created_at DESC
         OFFSET 50
       )`,
      [deviceId]
    );

    if (existingPull.rows.length) {
      return {
        pullId: existingPull.rows[0].pull_id,
        deviceId,
        status: 'pending',
        expiresAt: existingPull.rows[0].expires_at,
        fcm_delivered: false,
        message: 'A location pull is already pending for this device'
      };
    }

    const pullId = `pull_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const nonce = crypto.randomBytes(16).toString('hex');
    const timestamp = new Date().toISOString();
    const expiresAt = new Date(Date.now() + 60000).toISOString();

    let fcmDelivered = false;

    if (device.fcm_token) {
      const commandPayload = {
        deviceId,
        pullId,
        command: 'GET_LOCATION',
        reason,
        timestamp,
        nonce,
        serverId: process.env.SERVER_ID || 'server-001',
        expiresAt,
        imei: device.imei
      };

      try {
        const signatureResult = await kmsSigningService.sign(commandPayload);
        const payload = {
          type: 'PULL_LOCATION',
          command: 'GET_LOCATION',
          pullId,
          reason,
          requestedBy: userId,
          timestamp,
          nonce,
          serverId: process.env.SERVER_ID || 'server-001',
          expiresAt,
          deviceImei: device.imei,
          imei: device.imei,
          hmacSignature: signatureResult.signature,
          signatureProvider: signatureResult.provider,
          signatureKeyId: signatureResult.keyId
        };
        const result = await fcmService.sendToDevice(device.fcm_token, payload);
        fcmDelivered = result.success;
        if (result.invalidToken) {
          await db.query(
            `UPDATE devices
             SET fcm_token_status = 'invalid',
                 app_uninstall_suspected_at = COALESCE(app_uninstall_suspected_at, NOW()),
                 device_health_status = 'app_removed_suspected',
                 updated_at = NOW()
             WHERE id = $1`,
            [deviceId]
          );
        }
      } catch (err) {
        logger.warn(`FCM delivery failed for location pull on device ${deviceId}: ${err.message}`);
      }
    } else {
      logger.warn(
        `Device ${deviceId} has no FCM token — location pull queued without push delivery`
      );
    }

    await db.query(
      `INSERT INTO location_pull_requests (device_id, pull_id, reason, requested_by, status, requested_at, expires_at)
       VALUES ($1, $2, $3, $4, 'pending', NOW(), $5)`,
      [deviceId, pullId, reason || 'manual_pull', userId, expiresAt]
    );

    logger.info(`Location pull requested for device ${deviceId}`, { pullId, reason });

    await this.logAuditEvent({
      actor: userId,
      action: 'PULL_LOCATION',
      deviceId,
      metadata: { pullId, reason, nonce }
    });

    return {
      pullId,
      deviceId,
      status: 'pending',
      expiresAt,
      fcm_delivered: fcmDelivered,
      message: fcmDelivered
        ? 'Location pull sent — device should respond within 60 seconds'
        : 'Pull request queued — device will report location on next check-in'
    };
  }

  async recordLocationReport(deviceId, locationData) {
    const { latitude, longitude, accuracy, timestamp, battery_level, pull_id } = locationData;

    // Validate coordinate bounds
    const lat = parseFloat(latitude);
    const lon = parseFloat(longitude);
    if (isNaN(lat) || lat < -90 || lat > 90) {
      throw new Error('Invalid latitude: must be a number between -90 and 90');
    }
    if (isNaN(lon) || lon < -180 || lon > 180) {
      throw new Error('Invalid longitude: must be a number between -180 and 180');
    }

    const device = await deviceService.getDeviceById(deviceId);
    if (!device) {
      throw new Error('Device not found');
    }

    const client = await db.getClient();
    let locationId;
    let completedPullId = null;
    try {
      await client.query('BEGIN');

      await client.query(
        `UPDATE location_pull_requests
         SET status = 'expired'
         WHERE device_id = $1
           AND status = 'pending'
           AND expires_at <= NOW()`,
        [deviceId]
      );

      const pendingPull = pull_id
        ? await client.query(
            `SELECT id, pull_id FROM location_pull_requests
           WHERE device_id = $1 AND pull_id = $2 AND status = 'pending'
           LIMIT 1
           FOR UPDATE`,
            [deviceId, pull_id]
          )
        : await client.query(
            `SELECT id, pull_id FROM location_pull_requests
           WHERE device_id = $1 AND status = 'pending' AND expires_at > NOW()
           ORDER BY requested_at DESC LIMIT 1
           FOR UPDATE`,
            [deviceId]
          );

      if (pendingPull.rows.length > 0) {
        completedPullId = pendingPull.rows[0].pull_id;
        await client.query(
          `UPDATE location_pull_requests SET status = 'completed', responded_at = NOW() WHERE id = $1`,
          [pendingPull.rows[0].id]
        );
      }

      const result = await client.query(
        `INSERT INTO location_reports (device_id, latitude, longitude, accuracy, timestamp, battery_level, pull_id)
         VALUES ($1, $2, $3, $4, $5, $6, $7)
         RETURNING id`,
        [
          deviceId,
          lat,
          lon,
          accuracy,
          timestamp,
          battery_level || null,
          completedPullId || pull_id || null
        ]
      );
      locationId = result.rows[0].id;

      await client.query(
        `UPDATE devices SET last_location_lat = $1, last_location_lng = $2, last_location_time = $3,
         last_location_at = NOW(),
         last_seen_at = NOW(),
         device_health_status = 'online',
         fcm_token_status = CASE WHEN fcm_token IS NULL THEN fcm_token_status ELSE 'valid' END,
         app_uninstall_suspected_at = NULL,
         battery_level = $4,
         updated_at = NOW()
         WHERE id = $5`,
        [lat, lon, timestamp, battery_level || null, deviceId]
      );

      await client.query(
        `DELETE FROM location_pull_requests
         WHERE id IN (
           SELECT id FROM location_pull_requests
           WHERE device_id = $1
             AND status IN ('expired', 'completed')
           ORDER BY created_at DESC
           OFFSET 50
         )`,
        [deviceId]
      );

      await client.query('COMMIT');
    } catch (err) {
      await client.query('ROLLBACK');
      throw err;
    } finally {
      client.release();
    }

    // Prune old location history (keep last 10)
    const historyCount = await db.query(
      `SELECT COUNT(*) FROM location_reports WHERE device_id = $1`,
      [deviceId]
    );
    if (parseInt(historyCount.rows[0].count, 10) > 10) {
      await db.query(
        `DELETE FROM location_reports WHERE id IN (
           SELECT id FROM location_reports WHERE device_id = $1
           ORDER BY timestamp ASC LIMIT $2
         )`,
        [deviceId, parseInt(historyCount.rows[0].count, 10) - 10]
      );
    }

    logger.info(`Location recorded for device ${deviceId}`, { latitude: lat, longitude: lon });

    emitLocationReported(device, {
      pullId: completedPullId || pull_id || null,
      latitude: lat,
      longitude: lon,
      accuracy,
      timestamp
    });

    let alert = null;
    let geofenceTriggered = false;

    const geofence = await this.getActiveGeofence(deviceId);
    if (geofence) {
      const outsideGeofence = await this.checkGeofenceViolation(lat, lon, geofence);
      if (outsideGeofence) {
        geofenceTriggered = true;
        alert = await this.createGeofenceAlert(deviceId, geofence, lat, lon);
      }
    }

    return {
      locationId,
      geofenceTriggered,
      alert
    };
  }

  async getLocationHistory(deviceId, limit = 10) {
    const result = await db.query(
      `SELECT lr.id, lr.latitude, lr.longitude, lr.accuracy, lr.timestamp, lr.battery_level, lr.pull_id,
              lpr.reason as pull_reason, lpr.requested_by
       FROM location_reports lr
       LEFT JOIN location_pull_requests lpr ON lr.pull_id = lpr.pull_id
       WHERE lr.device_id = $1
       ORDER BY lr.timestamp DESC
       LIMIT $2`,
      [deviceId, limit]
    );

    return result.rows.map((row) => ({
      id: row.id,
      latitude: row.latitude,
      longitude: row.longitude,
      accuracy: row.accuracy,
      timestamp: row.timestamp,
      batteryLevel: row.battery_level,
      pullId: row.pull_id,
      pullReason: row.pull_reason,
      requestedBy: row.requested_by
    }));
  }

  async setGeofence(deviceId, geofenceData, userId) {
    const device = await deviceService.getDeviceById(deviceId);
    if (!device) {
      throw new Error('Device not found');
    }

    if (geofenceData.type === 'circle') {
      if (
        geofenceData.center_latitude === undefined ||
        geofenceData.center_longitude === undefined ||
        !geofenceData.radius_meters
      ) {
        throw new Error(
          'Circle geofence requires center_latitude, center_longitude, and radius_meters'
        );
      }
    } else if (geofenceData.type === 'polygon') {
      if (!geofenceData.coordinates || geofenceData.coordinates.length < 3) {
        throw new Error('Polygon geofence requires at least 3 coordinates');
      }
    }

    await db.query(`DELETE FROM geofences WHERE device_id = $1`, [deviceId]);

    const coordinatesJson =
      geofenceData.type === 'polygon' ? JSON.stringify(geofenceData.coordinates) : null;

    const result = await db.query(
      `INSERT INTO geofences (device_id, name, type, center_latitude, center_longitude, radius_meters, coordinates, enabled, created_by, created_at)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, NOW())
       RETURNING *`,
      [
        deviceId,
        geofenceData.name,
        geofenceData.type,
        geofenceData.center_latitude || null,
        geofenceData.center_longitude || null,
        geofenceData.radius_meters || null,
        coordinatesJson,
        geofenceData.enabled,
        userId
      ]
    );

    logger.info(`Geofence set for device ${deviceId}`, {
      name: geofenceData.name,
      type: geofenceData.type
    });

    await this.logAuditEvent({
      actor: userId,
      action: 'SET_GEOFENCE',
      deviceId,
      metadata: { name: geofenceData.name, type: geofenceData.type }
    });

    return this.formatGeofence(result.rows[0]);
  }

  async getGeofence(deviceId) {
    const result = await db.query(
      `SELECT g.*, u.name as created_by_name
       FROM geofences g
       LEFT JOIN users u ON g.created_by = u.id
       WHERE g.device_id = $1
       ORDER BY g.created_at DESC
       LIMIT 1`,
      [deviceId]
    );

    if (result.rows.length === 0) {
      return null;
    }

    return this.formatGeofence(result.rows[0]);
  }

  async getActiveGeofence(deviceId) {
    const result = await db.query(
      `SELECT * FROM geofences WHERE device_id = $1 AND enabled = true`,
      [deviceId]
    );

    return result.rows.length > 0 ? result.rows[0] : null;
  }

  async deleteGeofence(deviceId, userId) {
    await db.query(`DELETE FROM geofences WHERE device_id = $1`, [deviceId]);
    logger.info(`Geofence deleted for device ${deviceId}`);

    await this.logAuditEvent({
      actor: userId || 'system',
      action: 'DELETE_GEOFENCE',
      deviceId,
      metadata: {}
    });
  }

  async checkGeofenceViolation(latitude, longitude, geofence) {
    if (geofence.type === 'circle') {
      const distance = this.haversineDistance(
        latitude,
        longitude,
        geofence.center_latitude,
        geofence.center_longitude
      );
      return distance > geofence.radius_meters;
    }
    if (geofence.type === 'polygon') {
      return !this.pointInPolygon(latitude, longitude, geofence.coordinates);
    }
    return false;
  }

  haversineDistance(lat1, lon1, lat2, lon2) {
    const R = 6371000;
    const dLat = this.toRad(lat2 - lat1);
    const dLon = this.toRad(lon2 - lon1);
    const a =
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(this.toRad(lat1)) *
        Math.cos(this.toRad(lat2)) *
        Math.sin(dLon / 2) *
        Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  }

  toRad(deg) {
    return deg * (Math.PI / 180);
  }

  pointInPolygon(lat, lng, coordinates) {
    let inside = false;
    const n = coordinates.length;

    for (let i = 0, j = n - 1; i < n; j = i++) {
      const xi = coordinates[i].longitude;
      const yi = coordinates[i].latitude;
      const xj = coordinates[j].longitude;
      const yj = coordinates[j].latitude;

      const intersect = yi > lat !== yj > lat && lng < ((xj - xi) * (lat - yi)) / (yj - yi) + xi;
      if (intersect) inside = !inside;
    }

    return inside;
  }

  async createGeofenceAlert(deviceId, geofence, latitude, longitude) {
    const device = await deviceService.getDeviceById(deviceId);
    if (!device) return null;

    if (device.status !== 'locked') {
      logger.info(`Device ${deviceId} outside geofence but not locked — no alert`);
      return null;
    }

    const alertId = `gf_alert_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    await db.query(
      `INSERT INTO geofence_alerts (device_id, geofence_id, alert_id, latitude, longitude, triggered_at, acknowledged)
       VALUES ($1, $2, $3, $4, $5, NOW(), false)`,
      [deviceId, geofence.id, alertId, latitude, longitude]
    );

    const payload = {
      type: 'GEOFENCE_ALERT',
      alertId,
      deviceId,
      geofenceName: geofence.name,
      latitude,
      longitude,
      timestamp: new Date().toISOString(),
      message: `Device has left ${geofence.name} boundary while locked`
    };

    if (device.dealer_id) {
      const dealerResult = await db.query(
        `SELECT u.fcm_token FROM users u WHERE u.dealer_id = $1 AND u.role = 'dealer' LIMIT 1`,
        [device.dealer_id]
      );

      if (dealerResult.rows.length > 0 && dealerResult.rows[0].fcm_token) {
        await fcmService.sendToDevice(dealerResult.rows[0].fcm_token, payload);
      }
    }

    await db.query(
      `INSERT INTO alerts (dealer_id, device_id, alert_type, title, message, metadata, status, created_at)
       VALUES ($1, $2, 'GEOFENCE_VIOLATION', $3, $4, $5, 'active', NOW())`,
      [
        device.dealer_id,
        deviceId,
        'Geofence Alert',
        payload.message,
        JSON.stringify({ alertId, latitude, longitude, geofenceName: geofence.name })
      ]
    );

    logger.warn(`Geofence alert created for device ${deviceId}`, {
      alertId,
      geofence: geofence.name
    });

    await this.logAuditEvent({
      actor: 'system',
      action: 'GEOFENCE_ALERT',
      deviceId,
      metadata: { alertId, latitude, longitude, geofenceName: geofence.name }
    });

    return {
      alertId,
      type: 'GEOFENCE_VIOLATION',
      message: payload.message,
      latitude,
      longitude,
      geofenceName: geofence.name
    };
  }

  async scheduleAutoLocation(deviceId) {
    const queue = this.getAutoLocationQueue();

    const existingJob = await queue.getRepeatableJobs();
    const existingForDevice = existingJob.find((j) => j.name === `auto-location-${deviceId}`);
    if (existingForDevice) {
      await queue.removeRepeatableByKey(existingForDevice.key);
    }

    const job = await queue.add(
      `auto-location-${deviceId}`,
      { deviceId, reason: 'auto_scheduled', scheduledAt: new Date().toISOString() },
      {
        repeat: { cron: '0 */6 * * *' },
        jobId: `auto-location-${deviceId}`
      }
    );

    logger.info(`Auto-location scheduled for device ${deviceId}`, { jobId: job.id });
    return job;
  }

  async cancelAutoLocation(deviceId) {
    const queue = this.getAutoLocationQueue();
    const existingJob = await queue.getRepeatableJobs();
    const existingForDevice = existingJob.find((j) => j.name === `auto-location-${deviceId}`);

    if (existingForDevice) {
      await queue.removeRepeatableByKey(existingForDevice.key);
      logger.info(`Auto-location cancelled for device ${deviceId}`);
    }
  }

  async processAutoLocationJob(job) {
    const { deviceId, reason } = job.data;

    try {
      const device = await deviceService.getDeviceById(deviceId);
      if (!device) {
        logger.warn(`Device ${deviceId} not found for auto-location`);
        return;
      }

      const currentLockLevel = device.lock_level || 'NONE';
      if (!AUTO_LOCATION_LOCK_LEVELS.has(currentLockLevel)) {
        logger.info(`Device ${deviceId} not in Full Lock — skipping auto-location`);
        await this.cancelAutoLocation(deviceId);
        return;
      }

      await this.pullLocationNow(deviceId, reason || 'auto_location_6h', 'system');

      logger.info(`Auto-location pulled for device ${deviceId}`);
    } catch (error) {
      logger.error(`Auto-location job failed for device ${deviceId}:`, error);
      throw error;
    }
  }

  formatGeofence(row) {
    return {
      id: row.id,
      deviceId: row.device_id,
      name: row.name,
      type: row.type,
      centerLatitude: row.center_latitude,
      centerLongitude: row.center_longitude,
      radiusMeters: row.radius_meters,
      coordinates: row.coordinates ? JSON.parse(row.coordinates) : null,
      enabled: row.enabled,
      createdBy: row.created_by,
      createdByName: row.created_by_name,
      createdAt: row.created_at
    };
  }

  async logAuditEvent({ actor, action, deviceId, metadata = {}, result = 'success' }) {
    try {
      await db.query(
        `INSERT INTO audit_log (actor, action, device_id, metadata, result, created_at)
         VALUES ($1, $2, $3, $4, $5, NOW())`,
        [actor, action, deviceId, JSON.stringify(metadata), result]
      );
    } catch (error) {
      logger.error('Failed to write audit log:', error);
    }
  }

  async initAutoLocationWorker() {
    const queue = this.getAutoLocationQueue();

    queue.process(async (job) => {
      await this.processAutoLocationJob(job);
    });

    logger.info('Auto-location worker initialized');
  }
}

module.exports = new LocationService();

const amapiService = require('../devices/amapiService');
const { getMessaging } = require('../notifications/fcm.service');
const db = require('../../config/database');
const logger = require('../../utils/logger');
const { LOCK_LEVELS } = require('./lockVerificationService');
const { insertDeliveryLog, getDeviceDeliveryInfo } = require('./lockDeliveryRepository');

let _pautService = null;
function getPautService() {
  if (!_pautService) _pautService = require('./pautService');
  return _pautService;
}

function sleep(ms) {
  return new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

class LockDeliveryService {
  buildFcmData(data) {
    return Object.fromEntries(
      Object.entries(data)
        .filter(([, value]) => value !== undefined && value !== null)
        .map(([key, value]) => [key, String(value)])
    );
  }

  async withRetry(operation, maxRetries = 3, baseDelay = 1000) {
    let attempt = 0;
    while (attempt < maxRetries) {
      try {
        return await operation();
      } catch (error) {
        attempt++;
        if (attempt >= maxRetries) {
          throw error;
        }
        const delay = baseDelay * 2 ** (attempt - 1);
        logger.warn(`Delivery attempt ${attempt} failed, retrying in ${delay}ms...`, {
          error: error.message
        });
        await sleep(delay);
      }
    }
  }

  async deliverCommand(deviceId, command, lockLevel) {
    const results = {
      fcm: { attempted: false, success: false, error: null },
      amapi: { attempted: false, success: false, error: null },
      paut: { attempted: false, success: false, error: null }
    };

    const deviceRow = await getDeviceDeliveryInfo(deviceId);
    if (!deviceRow) {
      throw new Error('Device not found for delivery');
    }
    const { fcm_token, amapi_device_name, imei } = deviceRow;

    results.fcm = await this.deliverViaFcm(deviceId, fcm_token, command, lockLevel);

    results.amapi = await this.deliverViaAmapi(deviceId, amapi_device_name, lockLevel);

    if (lockLevel !== LOCK_LEVELS.FULL_LOCK) {
      results.paut = await this.deliverPaut(deviceId, imei, lockLevel);
    } else {
      results.paut = {
        attempted: false,
        success: false,
        error: null,
        channel: 'PAUT',
        skipped: true
      };
    }

    const anySuccess = results.fcm.success || results.amapi.success || results.paut.success;

    await this.logDeliveryResult(deviceId, command, results);

    return { delivered: anySuccess, results };
  }

  async deliverViaFcm(deviceId, fcmToken, command, lockLevel) {
    const result = { attempted: true, success: false, error: null, channel: 'FCM' };

    if (!fcmToken) {
      result.error = 'No FCM token registered for device';
      return result;
    }

    try {
      const appCommand = this.toAppCommand(command.actionType, lockLevel);
      const message = {
        token: fcmToken,
        data: this.buildFcmData({
          type: 'LOCK_COMMAND',
          command: appCommand,
          commandType: command.actionType,
          lockLevel: lockLevel || 'FULL_LOCK',
          nonce: command.nonce,
          timestamp: String(command.timestamp),
          expiresAt: command.expiresAt,
          hmacSignature: command.hmacSignature,
          deviceImei: command.deviceImei
        }),
        android: {
          priority: 'high',
          ttl: 5 * 60 * 1000
        }
      };

      await this.withRetry(() => getMessaging().send(message));
      result.success = true;
      logger.info('FCM lock command delivered', { deviceId });
    } catch (error) {
      result.error = error.message;
      logger.error('FCM delivery failed after 3 attempts', { deviceId, error: error.message });
    }

    return result;
  }

  toAppCommand(actionType, lockLevel) {
    if (actionType === 'UNLOCK' || lockLevel === LOCK_LEVELS.NONE) {
      return 'UNLOCK';
    }
    if (lockLevel === LOCK_LEVELS.PARTIAL_LOCK || lockLevel === LOCK_LEVELS.REMINDER_MODE) {
      return 'PARTIAL_LOCK';
    }
    return 'LOCK';
  }

  async deliverViaAmapi(deviceId, amapiDeviceName, lockLevel) {
    const result = { attempted: true, success: false, error: null, channel: 'AMAPI' };

    if (!amapiDeviceName) {
      result.error = 'No AMAPI device name registered';
      return result;
    }

    try {
      await amapiService.initialize();
      const enterpriseId = process.env.AMAPI_ENTERPRISE_ID;

      const policyMap = {
        REMINDER_MODE: this.buildReminderModePolicy(),
        PARTIAL_LOCK: this.buildPartialLockPolicy(),
        FULL_LOCK: this.buildFullLockPolicy()
      };

      const policy = policyMap[lockLevel] || policyMap.FULL_LOCK;

      await this.withRetry(() =>
        amapiService.setDevicePolicy(enterpriseId, amapiDeviceName, policy)
      );
      result.success = true;
      logger.info('AMAPI policy applied', { deviceId, lockLevel });
    } catch (error) {
      result.error = error.message;
      logger.error('AMAPI delivery failed after 3 attempts', { deviceId, error: error.message });
    }

    return result;
  }

  async deliverPaut(deviceId, imei, lockLevel) {
    const result = { attempted: true, success: false, error: null, channel: 'PAUT' };

    if (!imei) {
      result.error = 'No IMEI registered for device';
      return result;
    }

    try {
      const paut = await getPautService().issueToken({ deviceId, imei, lockLevel });
      result.success = true;
      result.tokenId = paut.jti;
      logger.info('PAUT issued for offline unlock', { deviceId, expiresAt: paut.expiresAt });
    } catch (error) {
      result.error = error.message;
      logger.error('PAUT issuance failed', { deviceId, error: error.message });
    }

    return result;
  }

  buildReminderModePolicy() {
    return {
      statusBarSettings: { disabled: false },
      statusBarNotifications: [
        {
          title: 'EMI Payment Reminder',
          text: 'Your EMI payment is overdue. Please make a payment to avoid device restrictions.',
          userCanDismiss: false
        }
      ]
    };
  }

  buildPartialLockPolicy() {
    // Read blocked apps from env for configurability (white-labeling support)
    const blockedApps = (
      process.env.PARTIAL_LOCK_BLOCKED_APPS ||
      'com.android.chrome,com.google.android.youtube,com.instagram.android,com.facebook.katana,com.whatsapp'
    )
      .split(',')
      .map((pkg) => ({ packageName: pkg.trim() }));

    return {
      installAppsDisabled: true,
      uninstallAppsDisabled: true,
      statusBarSettings: { disabled: true },
      statusBarNotifications: [
        {
          title: 'EMI Payment Required',
          text: 'Your device is partially locked due to overdue EMI. Contact your dealer.',
          userCanDismiss: false
        }
      ],
      disabledApplications: blockedApps
    };
  }

  buildFullLockPolicy() {
    // NOTE: Do NOT use preferredActivities with hardcoded com.android.launcher —
    // this crashes on MIUI, ColorOS, FuntouchOS, and other OEM ROMs.
    // Kiosk enforcement is handled by the EMI app itself via lockTask mode (FCM command).
    // AMAPI is used here only to enforce device-level restrictions.
    const lockTaskPackages = (process.env.FULL_LOCK_KIOSK_PACKAGES || 'com.emilocker.user')
      .split(',')
      .map((pkg) => pkg.trim());

    return {
      statusBarSettings: { disabled: true },
      statusBarNotifications: [
        {
          title: 'Device Locked — EMI Overdue',
          text: 'This device is locked due to non-payment. Contact your dealer to resolve.',
          userCanDismiss: false
        }
      ],
      installAppsDisabled: true,
      uninstallAppsDisabled: true,
      usbDataAccessDisabled: true,
      screenCaptureDisabled: true,
      adjustVolumeDisabled: true,
      factoryResetDisabled: true,
      factoryResetProtection: true,
      kioskCustomization: {
        powerButtonActions: 'POWER_BUTTON_AVAILABLE',
        systemErrorWarnings: 'ERROR_AND_WARNINGS_DISABLED',
        systemNavigation: 'NAVIGATION_DISABLED',
        statusBar: 'NOTIFICATIONS_AND_SYSTEM_INFO_DISABLED'
      },
      lockTaskPolicy: {
        packages: lockTaskPackages
      },
      wipeOnFailureEnabled: false
    };
  }

  async logDeliveryResult(deviceId, command, results) {
    try {
      await insertDeliveryLog({
        deviceId,
        commandNonce: command.nonce,
        commandType: command.actionType,
        fcmResult: results.fcm,
        amapiResult: results.amapi,
        pautResult: results.paut
      });
    } catch (error) {
      logger.error('Failed to log delivery result', { deviceId, error: error.message });
    }
  }

  async deliverNotification(deviceId, type, title, body) {
    const device = await db.query(`SELECT fcm_token FROM devices WHERE id = $1`, [deviceId]);

    if (device.rows.length === 0 || !device.rows[0].fcm_token) {
      return { success: false, error: 'No FCM token' };
    }

    try {
      await getMessaging().send({
        token: device.rows[0].fcm_token,
        data: this.buildFcmData({
          type,
          title,
          body
        }),
        android: { priority: 'high' }
      });
      return { success: true };
    } catch (error) {
      logger.error('Notification delivery failed', { deviceId, error: error.message });
      return { success: false, error: error.message };
    }
  }

  async deliverOverlayCommand(deviceId, type, title, body) {
    const device = await db.query(`SELECT fcm_token FROM devices WHERE id = $1`, [deviceId]);

    if (device.rows.length === 0 || !device.rows[0].fcm_token) {
      return { success: false, error: 'No FCM token' };
    }

    try {
      await getMessaging().send({
        token: device.rows[0].fcm_token,
        data: this.buildFcmData({
          type,
          title,
          body,
          overlay: 'true',
          dismissible: 'false'
        }),
        android: { priority: 'high' }
      });
      return { success: true };
    } catch (error) {
      logger.error('Overlay delivery failed', { deviceId, error: error.message });
      return { success: false, error: error.message };
    }
  }
}

module.exports = new LockDeliveryService();

const cron = require('node-cron');
const db = require('../../config/database');
const logger = require('../../utils/logger');
const lockDeliveryService = require('./lockDeliveryService');
const lockCommandService = require('./lockCommandService');

const LOCK_LEVELS = {
  NONE: 'NONE',
  REMINDER_MODE: 'REMINDER_MODE',
  PARTIAL_LOCK: 'PARTIAL_LOCK',
  FULL_LOCK: 'FULL_LOCK'
};

class LockSchedulerService {
  constructor() {
    this.jobs = [];
    this.started = false;
  }

  start() {
    if (this.started) {
      logger.warn('Lock scheduler already started');
      return;
    }

    const cronSchedule = process.env.AUTO_LOCK_CRON || '0 0 * * *';

    const dailyJob = cron.schedule(
      cronSchedule,
      async () => {
        logger.info('Auto-lock scheduler triggered');
        await this.runDailyCheck();
      },
      { scheduled: true, timezone: process.env.TZ || 'UTC' }
    );

    this.jobs.push(dailyJob);

    // Grace expiry check — runs every 5 minutes.
    // Finds devices whose dealer-issued grace period has expired and re-locks them.
    const graceJob = cron.schedule(
      '*/5 * * * *',
      async () => {
        await this.runGraceExpiryCheck();
      },
      { scheduled: true, timezone: process.env.TZ || 'UTC' }
    );

    this.jobs.push(graceJob);

    this.started = true;
    logger.info(`Lock scheduler started with cron: ${cronSchedule} + grace expiry every 5 min`);
  }

  stop() {
    this.jobs.forEach((job) => job.stop());
    this.jobs = [];
    this.started = false;
    logger.info('Lock scheduler stopped');
  }

  async runDailyCheck() {
    try {
      const devices = await db.query(
        `SELECT d.id, d.imei, d.fcm_token, d.amapi_device_name, d.lock_level,
                d.dealer_id,
                (es.start_date + ((COALESCE(paid.installments_paid, 0) || ' months')::interval)) AS next_due_date,
                es.grace_days AS grace_period_days
         FROM devices d
         JOIN emi_schedules es ON d.id = es.device_id AND es.status = 'active'
         LEFT JOIN LATERAL (
           SELECT COUNT(*) AS installments_paid
           FROM emi_payments ep
           WHERE ep.emi_schedule_id = es.id AND ep.status = 'completed'
         ) paid ON TRUE
         WHERE d.status NOT IN ('decoupled', 'disabled')
           AND COALESCE(paid.installments_paid, 0) < es.duration`
      );

      logger.info(`Auto-lock scheduler checking ${devices.rows.length} devices`);

      let processed = 0;
      let locked = 0;
      let notified = 0;
      let errors = 0;

      for (const device of devices.rows) {
        try {
          const result = await this.processDevice(device);
          processed++;
          if (result.locked) locked++;
          if (result.notified) notified++;
        } catch (error) {
          errors++;
          logger.error('Auto-lock device processing failed', {
            deviceId: device.id,
            error: error.message
          });
        }
      }

      logger.info('Auto-lock scheduler completed', { processed, locked, notified, errors });
    } catch (error) {
      logger.error('Auto-lock scheduler run failed', { error: error.message });
    }
  }

  async processDevice(device) {
    const { id: deviceId, imei, next_due_date, grace_period_days } = device;
    const graceDays = grace_period_days || 7;

    const now = new Date();
    const dueDate = new Date(next_due_date);
    const overdueDays = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));

    const schedule = this.getScheduleAction(overdueDays);

    if (!schedule) {
      return { locked: false, notified: false };
    }

    switch (schedule.action) {
      case 'REMINDER_PUSH':
        await this.sendReminderNotification(deviceId, overdueDays);
        return { locked: false, notified: true };

      case 'WARNING_OVERLAY':
        await this.sendWarningOverlay(deviceId, overdueDays);
        return { locked: false, notified: true };

      case 'OVERDUE_ALERT':
        await this.sendOverdueAlert(deviceId, overdueDays);
        return { locked: false, notified: true };

      case 'APPLY_REMINDER':
        await this.applyLock(device, LOCK_LEVELS.REMINDER_MODE, 'auto_lock_reminder');
        return { locked: true, notified: false };

      case 'APPLY_PARTIAL':
        await this.applyLock(device, LOCK_LEVELS.PARTIAL_LOCK, 'auto_lock_partial');
        return { locked: true, notified: false };

      case 'APPLY_FULL':
        await this.applyLock(device, LOCK_LEVELS.FULL_LOCK, 'auto_lock_full');
        return { locked: true, notified: false };

      case 'APPLY_FULL_ADMIN_FLAG':
        await this.applyLock(device, LOCK_LEVELS.FULL_LOCK, 'auto_lock_full_admin_review');
        await this.flagForAdminReview(deviceId, overdueDays);
        return { locked: true, notified: false };

      default:
        return { locked: false, notified: false };
    }
  }

  getScheduleAction(overdueDays) {
    if (overdueDays >= -7 && overdueDays < -3)
      return { action: 'REMINDER_PUSH', level: LOCK_LEVELS.NONE };
    if (overdueDays >= -3 && overdueDays < 0)
      return { action: 'WARNING_OVERLAY', level: LOCK_LEVELS.NONE };
    if (overdueDays === 0) return { action: 'OVERDUE_ALERT', level: LOCK_LEVELS.NONE };
    if (overdueDays >= 1 && overdueDays < 3)
      return { action: 'APPLY_REMINDER', level: LOCK_LEVELS.REMINDER_MODE };
    if (overdueDays >= 3 && overdueDays < 7)
      return { action: 'APPLY_PARTIAL', level: LOCK_LEVELS.PARTIAL_LOCK };
    if (overdueDays >= 7 && overdueDays < 14)
      return { action: 'APPLY_FULL', level: LOCK_LEVELS.FULL_LOCK };
    if (overdueDays >= 14) return { action: 'APPLY_FULL_ADMIN_FLAG', level: LOCK_LEVELS.FULL_LOCK };
    return null;
  }

  async sendReminderNotification(deviceId, overdueDays) {
    await lockDeliveryService.deliverNotification(
      deviceId,
      'EMI_REMINDER',
      'EMI Payment Reminder',
      `Your EMI payment is due in ${Math.abs(overdueDays)} days. Please make your payment on time.`
    );
  }

  async sendWarningOverlay(deviceId, overdueDays) {
    await lockDeliveryService.deliverOverlayCommand(
      deviceId,
      'EMI_WARNING',
      'EMI Payment Warning',
      `Your EMI payment is due in ${Math.abs(overdueDays)} days. Failure to pay may result in device restrictions.`
    );
  }

  async sendOverdueAlert(deviceId, overdueDays) {
    await lockDeliveryService.deliverOverlayCommand(
      deviceId,
      'EMI_OVERDUE',
      'EMI Payment Overdue',
      'Your EMI payment is due today. Please pay immediately to avoid device lock.'
    );
  }

  toDbLockLevel(lockLevel) {
    if (lockLevel === LOCK_LEVELS.FULL_LOCK) return 'FULL';
    if (lockLevel === LOCK_LEVELS.PARTIAL_LOCK || lockLevel === LOCK_LEVELS.REMINDER_MODE)
      return 'SOFT';
    return 'NONE';
  }

  toDbStatus(lockLevel) {
    if (lockLevel === LOCK_LEVELS.FULL_LOCK) return 'locked';
    if (lockLevel === LOCK_LEVELS.PARTIAL_LOCK) return 'partial_lock';
    if (lockLevel === LOCK_LEVELS.REMINDER_MODE) return 'reminder';
    return 'enrolled';
  }

  async applyLock(device, lockLevel, reason) {
    const deviceId = device.id;
    const { imei } = device;
    const command = await lockCommandService.generateSignedCommand({
      deviceImei: imei,
      actionType: 'AUTO_LOCK',
      lockLevel,
      metadata: { reason, source: 'scheduler' }
    });

    await lockDeliveryService.deliverCommand(deviceId, command, lockLevel);

    await db.query(
      `UPDATE devices
       SET lock_level = $1,
           status = $2,
           lock_reason = $3,
           locked_at = NOW(),
           updated_at = NOW()
       WHERE id = $4`,
      [this.toDbLockLevel(lockLevel), this.toDbStatus(lockLevel), reason, deviceId]
    );

    try {
      const sseService = require('../sse/sseService');
      sseService.emitDeviceLocked({
        id: deviceId,
        imei,
        device_name: device.amapi_device_name,
        lock_level: lockLevel,
        lock_reason: reason,
        dealer_id: device.dealer_id
      });
    } catch (e) {
      logger.warn('SSE emit failed during auto-lock', { deviceId, error: e.message });
    }

    logger.info('Auto-lock applied', { deviceId, lockLevel, reason });
  }

  async flagForAdminReview(deviceId, overdueDays) {
    await db.query(
      `INSERT INTO admin_escalations (entity_type, entity_id, reason, note, status, created_at)
       VALUES ('device', $1, 'AUTO_LOCK_EXTENDED_OVERDUE', $2, 'pending', NOW())`,
      [deviceId, `Device overdue by ${overdueDays} days — requires admin review`]
    );

    logger.warn('Device flagged for admin review', { deviceId, overdueDays });
  }

  // Runs every 5 minutes. Finds devices whose dealer-issued grace period has expired
  // and sends a re-lock command via FCM. Clears grace_expires_at after re-locking.
  async runGraceExpiryCheck() {
    try {
      const expired = await db.query(
        `SELECT id, fcm_token, model, brand
         FROM devices
         WHERE grace_expires_at IS NOT NULL
           AND grace_expires_at < NOW()
           AND status NOT IN ('decoupled', 'disabled')`
      );

      if (!expired.rows.length) return;

      logger.info(`Grace expiry check: ${expired.rows.length} device(s) to re-lock`);

      for (const device of expired.rows) {
        try {
          // Send FCM re-lock command
          try {
            await lockCommandService.sendLockCommand(device.id, {
              reason: 'GRACE_EXPIRED',
              lock_level: 'FULL_LOCK'
            });
          } catch (e) {
            logger.warn('FCM re-lock failed during grace expiry', {
              deviceId: device.id,
              error: e.message
            });
          }

          // Clear grace_expires_at and update status
          await db.query(
            `UPDATE devices
             SET grace_expires_at = NULL,
                 status           = 'locked',
                 updated_at       = NOW()
             WHERE id = $1`,
            [device.id]
          );

          // Audit log
          await db.query(
            `INSERT INTO audit_log (actor, action, device_id, metadata, result, created_at)
             VALUES ('system', 'GRACE_EXPIRED_AUTO_RELOCK', $1, $2, 'success', NOW())`,
            [device.id, JSON.stringify({ model: device.model, brand: device.brand })]
          );

          logger.info('Grace expired — device re-locked', { deviceId: device.id });
        } catch (err) {
          logger.error('Grace expiry re-lock failed', { deviceId: device.id, error: err.message });
        }
      }
    } catch (err) {
      logger.error('Grace expiry check run failed', { error: err.message });
    }
  }
}

module.exports = new LockSchedulerService();

const db = require('../../config/database');
const logger = require('../../utils/logger');

const LOCK_LEVELS = {
  NONE: 'NONE',
  REMINDER_MODE: 'REMINDER_MODE',
  PARTIAL_LOCK: 'PARTIAL_LOCK',
  FULL_LOCK: 'FULL_LOCK',
};

const LOCK_LEVEL_HIERARCHY = {
  [LOCK_LEVELS.NONE]: 0,
  [LOCK_LEVELS.REMINDER_MODE]: 1,
  [LOCK_LEVELS.PARTIAL_LOCK]: 2,
  [LOCK_LEVELS.FULL_LOCK]: 3,
};

const VALID_LOCK_REASONS = [
  'EMI_OVERDUE',
  'SUSPECTED_FRAUD',
  'SUSPECTED_SALE',
  'DEVICE_STOLEN',
  'TERMS_VIOLATION',
];

const ESCALATION_REASONS = ['SUSPECTED_FRAUD', 'SUSPECTED_SALE'];

const GRACE_PERIOD_DAYS = parseInt(process.env.GRACE_PERIOD_DAYS, 10) || 7;
const MAX_INVALID_REQUESTS = 3;
const INVALID_REQUEST_WINDOW_HOURS = 24;
const LOCK_ABUSE_GUARD_ENABLED = process.env.LOCK_ABUSE_GUARD_ENABLED === 'true';
const GPS_RADIUS_METERS = parseInt(process.env.GPS_RADIUS_METERS, 10) || 500;

class LockVerificationService {
  async verifyLockRequest({ deviceId, dealerId, dealerUserId, dealerIds, reason, note }) {
    const failures = [];

    const device = await this.getDeviceWithEmi(deviceId, dealerIds);
    if (!device) {
      return { valid: false, decision: 'REJECTED', failures: ['Device not found'] };
    }

    if (device.status === 'decoupled') {
      return { valid: false, decision: 'REJECTED', failures: ['Device is already decoupled'] };
    }

    // Manual dealer locks must work during testing. Payment-state gating belongs
    // in the EMI scheduler/business rules, not in this click path.
    const graceCheck = await this.checkGracePeriodExtension(deviceId);
    if (graceCheck.active) {
      failures.push('Grace period extension is active');
    }

    // During demo/testing, lock requests are idempotent: re-submitting a lock
    // should re-send the command instead of blocking on the current DB state.

    if (LOCK_ABUSE_GUARD_ENABLED) {
      const abuseCheck = await this.checkDealerAbuse(dealerUserId || dealerId);
      if (abuseCheck.abused) {
        failures.push(`Dealer submitted ${abuseCheck.count} invalid requests in the last ${INVALID_REQUEST_WINDOW_HOURS} hours`);
      }
    }

    if (ESCALATION_REASONS.includes(reason)) {
      await this.escalateToAdmin({ deviceId, dealerId, reason, note });
      return {
        valid: false,
        decision: 'ESCALATED',
        failures: [`Reason ${reason} escalated to admin for review`],
      };
    }

    if (failures.length > 0) {
      await this.recordInvalidRequest(dealerId, deviceId, reason, failures, dealerUserId || dealerId);
      return { valid: false, decision: 'REJECTED', failures };
    }

    return { valid: true, decision: 'APPROVED', failures: [] };
  }

  async getDeviceWithEmi(deviceId, dealerIds = null) {
    const ownershipClause = Array.isArray(dealerIds) && dealerIds.length
      ? 'AND d.dealer_id = ANY($2::uuid[])'
      : '';
    const params = Array.isArray(dealerIds) && dealerIds.length
      ? [deviceId, dealerIds]
      : [deviceId];
    const result = await db.query(
      `SELECT d.*, es.start_date as next_due_date, es.total_amount as total_emi_amount,
              COALESCE((SELECT SUM(amount) FROM emi_payments WHERE emi_schedule_id = es.id AND status = 'completed'), 0) as paid_amount,
              es.start_date, (es.start_date + (es.duration || ' months')::INTERVAL) as emi_end_date,
              es.duration as installments_total,
              (SELECT COUNT(*) FROM emi_payments WHERE emi_schedule_id = es.id AND status = 'completed') as installments_paid,
              es.grace_days as grace_period_days
       FROM devices d
       LEFT JOIN emi_schedules es ON d.id = es.device_id AND es.status = 'active'
       WHERE d.id = $1 ${ownershipClause}`,
      params
    );
    return result.rows[0] || null;
  }

  async checkEmiPaymentStatus(device) {
    if (!device.next_due_date) {
      return { current: true, overdueDays: 0 };
    }

    const now = new Date();
    const dueDate = new Date(device.next_due_date);
    const graceDays = device.grace_period_days || GRACE_PERIOD_DAYS;
    const graceEnd = new Date(dueDate);
    graceEnd.setDate(graceEnd.getDate() + graceDays);

    if (now <= graceEnd) {
      return { current: true, overdueDays: 0 };
    }

    const overdueDays = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));
    return { current: false, overdueDays };
  }

  async checkGracePeriodExtension(deviceId) {
    const result = await db.query(
      `SELECT id, granted_until, reason
       FROM grace_period_extensions
       WHERE device_id = $1 AND granted_until > NOW() AND status = 'active'
       ORDER BY granted_until DESC LIMIT 1`,
      [deviceId]
    );

    if (result.rows.length > 0) {
      return { active: true, extension: result.rows[0] };
    }
    return { active: false };
  }

  checkDeviceLockLevel(device, reason) {
    const normalizedCurrent = this.normalizeLockLevel(device.lock_level);
    const currentLevel = LOCK_LEVEL_HIERARCHY[normalizedCurrent] || 0;

    const reasonToLevel = {
      EMI_OVERDUE: LOCK_LEVELS.FULL_LOCK,
      DEVICE_STOLEN: LOCK_LEVELS.FULL_LOCK,
      TERMS_VIOLATION: LOCK_LEVELS.PARTIAL_LOCK,
      SUSPECTED_FRAUD: LOCK_LEVELS.REMINDER_MODE,
      SUSPECTED_SALE: LOCK_LEVELS.REMINDER_MODE,
    };

    const requestedLevel = LOCK_LEVEL_HIERARCHY[reasonToLevel[reason] || LOCK_LEVELS.FULL_LOCK];

    return {
      alreadyAtOrHigher: currentLevel >= requestedLevel,
      currentLevel: Object.keys(LOCK_LEVEL_HIERARCHY).find(k => LOCK_LEVEL_HIERARCHY[k] === currentLevel) || 'NONE',
      requestedLevel: Object.keys(LOCK_LEVEL_HIERARCHY).find(k => LOCK_LEVEL_HIERARCHY[k] === requestedLevel) || 'FULL_LOCK',
    };
  }

  normalizeLockLevel(lockLevel) {
    const aliases = {
      NONE: LOCK_LEVELS.NONE,
      SOFT: LOCK_LEVELS.PARTIAL_LOCK,
      FULL: LOCK_LEVELS.FULL_LOCK,
      WIPE: LOCK_LEVELS.FULL_LOCK,
      REMINDER_MODE: LOCK_LEVELS.REMINDER_MODE,
      PARTIAL_LOCK: LOCK_LEVELS.PARTIAL_LOCK,
      FULL_LOCK: LOCK_LEVELS.FULL_LOCK,
    };
    return aliases[lockLevel] || LOCK_LEVELS.NONE;
  }

  async checkDealerAbuse(dealerId) {
    const result = await db.query(
      `SELECT COUNT(*) as count
       FROM lock_requests
       WHERE requested_by = $1
         AND status = 'rejected'
         AND created_at > NOW() - ($2 || ' hours')::interval`,
      [dealerId, INVALID_REQUEST_WINDOW_HOURS]
    );

    const count = parseInt(result.rows[0].count, 10);
    return { abused: count >= MAX_INVALID_REQUESTS, count };
  }

  async checkDeviceGpsAtShop(deviceId, dealerId, reason) {
    const deviceGps = await db.query(
      `SELECT latitude, longitude, recorded_at FROM location_reports
       WHERE device_id = $1 ORDER BY timestamp DESC LIMIT 1`,
      [deviceId]
    );

    if (deviceGps.rows.length === 0) {
      return { atShop: false };
    }

    const dealer = await db.query(
      `SELECT shop_latitude, shop_longitude FROM dealers WHERE id = $1`,
      [dealerId]
    );

    if (dealer.rows.length === 0 || !dealer.rows[0].shop_latitude) {
      return { atShop: false };
    }

    const { latitude, longitude } = deviceGps.rows[0];
    const { shop_latitude, shop_longitude } = dealer.rows[0];

    const distance = this.calculateDistance(latitude, longitude, shop_latitude, shop_longitude);

    return { atShop: distance <= GPS_RADIUS_METERS, distance };
  }

  calculateDistance(lat1, lon1, lat2, lon2) {
    const R = 6371e3;
    const toRad = (deg) => (deg * Math.PI) / 180;
    const dLat = toRad(lat2 - lat1);
    const dLon = toRad(lon2 - lon1);
    const a =
      Math.sin(dLat / 2) ** 2 +
      Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  }

  async recordInvalidRequest(dealerId, deviceId, reason, failures, requestedBy = dealerId) {
    const reasonCodeMap = {
      'EMI_OVERDUE': 'emi_default',
      'SUSPECTED_FRAUD': 'fraud_detected',
      'SUSPECTED_SALE': 'other',
      'DEVICE_STOLEN': 'stolen_report',
      'TERMS_VIOLATION': 'policy_violation',
    };
    const reasonCode = reasonCodeMap[reason] || 'other';
    await db.query(
      `INSERT INTO lock_requests (dealer_id, requested_by, device_id, reason_code, note, status, rejection_reasons, created_at)
       VALUES ($1, $6, $2, $3, $4, 'rejected', $5, NOW())`,
      [dealerId, deviceId, reasonCode, null, JSON.stringify(failures), requestedBy]
    );
  }

  async escalateToAdmin({ deviceId, dealerId, reason, note }) {
    await db.query(
      `INSERT INTO admin_escalations (entity_type, entity_id, dealer_id, reason, note, status, created_at)
       VALUES ('device', $1, $2, $3, $4, 'pending', NOW())`,
      [deviceId, dealerId, reason, note || null]
    );

    logger.warn('Lock request escalated to admin', { deviceId, dealerId, reason });
  }

  async recordApprovedRequest(dealerId, deviceId, reason, note, requestedBy = dealerId) {
    const reasonCodeMap = {
      'EMI_OVERDUE': 'emi_default',
      'SUSPECTED_FRAUD': 'fraud_detected',
      'SUSPECTED_SALE': 'other',
      'DEVICE_STOLEN': 'stolen_report',
      'TERMS_VIOLATION': 'policy_violation',
    };
    const reasonCode = reasonCodeMap[reason] || 'other';
    const result = await db.query(
      `INSERT INTO lock_requests (dealer_id, requested_by, device_id, reason_code, note, status, created_at)
       VALUES ($1, $5, $2, $3, $4, 'approved', NOW())
       RETURNING id`,
      [dealerId, deviceId, reasonCode, note || null, requestedBy]
    );
    return result.rows[0].id;
  }

  getAutoLockLevel(overdueDays) {
    if (overdueDays <= -7) return { level: LOCK_LEVELS.NONE, action: 'REMINDER_PUSH' };
    if (overdueDays <= -3) return { level: LOCK_LEVELS.NONE, action: 'WARNING_OVERLAY' };
    if (overdueDays <= 0) return { level: LOCK_LEVELS.NONE, action: 'OVERDUE_ALERT' };
    if (overdueDays <= 1) return { level: LOCK_LEVELS.REMINDER_MODE, action: 'APPLY_LOCK' };
    if (overdueDays <= 3) return { level: LOCK_LEVELS.PARTIAL_LOCK, action: 'APPLY_LOCK' };
    if (overdueDays <= 7) return { level: LOCK_LEVELS.FULL_LOCK, action: 'APPLY_LOCK' };
    return { level: LOCK_LEVELS.FULL_LOCK, action: 'APPLY_LOCK_ADMIN_FLAG' };
  }

  getLockLevelHierarchy() {
    return LOCK_LEVEL_HIERARCHY;
  }
}

module.exports = new LockVerificationService();
module.exports.LOCK_LEVELS = LOCK_LEVELS;
module.exports.LOCK_LEVEL_HIERARCHY = LOCK_LEVEL_HIERARCHY;
module.exports.VALID_LOCK_REASONS = VALID_LOCK_REASONS;

const admin = require('firebase-admin');

let firebaseApp = null;

function initializeFCM() {
  if (firebaseApp) {
    return firebaseApp;
  }

  if (admin.apps.length > 0) {
    firebaseApp = admin.app();
    return firebaseApp;
  }

  const serviceAccount = {
    projectId: process.env.FIREBASE_PROJECT_ID,
    privateKey: process.env.FIREBASE_PRIVATE_KEY?.replace(/\\n/g, '\n'),
    clientEmail: process.env.FIREBASE_CLIENT_EMAIL,
  };

  firebaseApp = admin.initializeApp({
    credential: admin.credential.cert(serviceAccount),
    projectId: process.env.FIREBASE_PROJECT_ID,
  });

  return firebaseApp;
}

function getMessaging() {
  const app = initializeFCM();
  return app.messaging();
}

async function sendToDevice(fcmToken, payload) {
  const messaging = getMessaging();

  const message = {
    token: fcmToken,
    notification: payload.title && payload.body
      ? { title: payload.title, body: payload.body }
      : undefined,
    data: Object.fromEntries(
      Object.entries(payload).map(([k, v]) => [k, String(v)])
    ),
    android: {
      priority: 'high',
      // Only set android.notification for actual notification messages.
      // Setting it on data-only messages prevents onMessageReceived from firing in background.
      ...(payload.title && payload.body ? {
        notification: {
          channelId: 'emi_locker_high_priority',
          defaultSound: true,
          defaultVibrateTimings: true,
        },
      } : {}),
    },
    apns: {
      payload: {
        aps: {
          contentAvailable: 1,
          mutableContent: 1,
        },
      },
    },
  };

  try {
    const response = await messaging.send(message);
    return { messageId: response, success: true };
  } catch (error) {
    const err = error;
    console.error('FCM send error:', { code: err.code, message: err.message });
    const invalidToken = [
      'messaging/registration-token-not-registered',
      'messaging/invalid-registration-token',
      'messaging/invalid-argument',
    ].includes(err.code);
    return {
      messageId: '',
      success: false,
      code: err.code || '',
      error: err.message || 'FCM send failed',
      invalidToken,
    };
  }
}

async function sendMulticast(tokens, payload) {
  const messaging = getMessaging();

  const message = {
    tokens,
    notification: {
      title: payload.title,
      body: payload.body,
    },
    data: payload.data,
    android: {
      priority: 'high',
      notification: {
        channelId: 'emi_locker_high_priority',
      },
    },
  };

  try {
    const response = await messaging.sendEachForMulticast(message);
    return {
      successCount: response.successCount,
      failureCount: response.failureCount,
      errors: response.responses
        .filter(r => !r.success)
        .map(r => r.error),
    };
  } catch (error) {
    const err = error;
    console.error('FCM multicast error:', { code: err.code, message: err.message });
    throw error;
  }
}

function buildLockCommandPayload(
  deviceId,
  lockLevel,
  signature,
  nonce,
  imei,
  serial,
  soc_model
) {
  return {
    type: 'LOCK_COMMAND',
    command: lockLevel >= 7 ? 'FULL_LOCK' : lockLevel >= 3 ? 'PARTIAL_LOCK' : 'LOCK',
    lockLevel,
    timestamp: new Date().toISOString(),
    signature,
    nonce,
    imei,
    serial,
    soc_model,
    serverId: process.env.SERVER_ID || 'server-001',
  };
}

function buildUnlockCommandPayload(
  deviceId,
  signature,
  expiryHours = 48,
  nonce,
  imei,
  serial,
  soc_model
) {
  const now = new Date();
  const expiry = new Date(now.getTime() + expiryHours * 60 * 60 * 1000);

  return {
    type: 'UNLOCK_COMMAND',
    command: 'UNLOCK',
    timestamp: now.toISOString(),
    expiry: expiry.toISOString(),
    signature,
    nonce,
    imei,
    serial,
    soc_model,
    serverId: process.env.SERVER_ID || 'server-001',
  };
}

function buildReminderPayload(daysUntilDue, amountDue, dueDate, dealerContact) {
  return {
    type: 'PAYMENT_REMINDER',
    title: 'Payment Reminder',
    body: `Payment of ${amountDue} due in ${daysUntilDue} days`,
    daysUntilDue,
    amountDue,
    dueDate,
    dealerContact,
    clickAction: 'EMI_PAYMENT',
  };
}

function buildDealerMessagePayload(message, dealerId, dealerName) {
  return {
    type: 'DEALER_MESSAGE',
    command: 'MESSAGE',
    message,
    dealerId,
    dealerName,
    timestamp: new Date().toISOString(),
    priority: 'high',
  };
}

module.exports = {
  initializeFCM,
  getMessaging,
  sendToDevice,
  sendMulticast,
  buildLockCommandPayload,
  buildUnlockCommandPayload,
  buildReminderPayload,
